328	async function resolveContinuationOwner(input: {
329	  specPackRoot: string;
330	  provider: ProviderName;
331	  sessionId: string;
332	}): Promise<string | null> {
333	  const artifactsRoot = join(resolve(input.specPackRoot), "artifacts");
334	  if (!(await pathExists(artifactsRoot))) {
335	    return null;
336	  }
337	
338	  const groups = await readdir(artifactsRoot, { withFileTypes: true });
339	  for (const group of groups) {
340	    if (!group.isDirectory()) {
341	      continue;
342	    }
343	
344	    const groupPath = join(artifactsRoot, group.name);
345	    const entries = await readdir(groupPath, { withFileTypes: true });
346	    for (const entry of entries) {
347	      if (!entry.isFile() || !entry.name.endsWith(".json")) {
348	        continue;
349	      }
350	
351	      try {
352	        const content = JSON.parse(
353	          await readTextFile(join(groupPath, entry.name))
354	        ) as {
355	          result?: {
356	            continuation?: {
357	              provider?: string;
358	              sessionId?: string;
359	              storyId?: string;
360	            };
361	          };
362	        };
363	        const continuation = content.result?.continuation;
364	        if (
365	          continuation?.provider === input.provider &&
366	          continuation?.sessionId === input.sessionId
367	        ) {
368	          return continuation.storyId ?? group.name;
369	        }
370	      } catch {}
371	    }
372	  }
373	
374	  return null;
375	}
