225	export function cliResultEnvelopeSchema<T extends z.ZodTypeAny>(resultSchema: T) {
226	  return z
227	    .object({
228	      command: z.string().min(1),
229	      version: z.literal(1),
230	      status: cliStatusSchema,
231	      outcome: z.string().min(1),
232	      result: resultSchema.optional(),
233	      errors: z.array(cliErrorSchema),
234	      warnings: z.array(z.string()),
235	      artifacts: z.array(cliArtifactRefSchema),
236	      startedAt: z.string().min(1),
237	      finishedAt: z.string().min(1),
238	    })
239	    .superRefine((value, ctx) => {
240	      const expectedStatus = statusForOutcome(value.outcome);
241	      if (expectedStatus !== value.status) {
242	        ctx.addIssue({
243	          code: z.ZodIssueCode.custom,
244	          message: `Envelope status '${value.status}' does not match outcome '${value.outcome}'`,
245	          path: ["status"],
246	        });
247	      }
248	
249	      if (
250	        value.result &&
251	        typeof value.result === "object" &&
252	        "outcome" in value.result &&
253	        typeof value.result.outcome === "string" &&
254	        value.result.outcome !== value.outcome
255	      ) {
256	        ctx.addIssue({
257	          code: z.ZodIssueCode.custom,
258	          message: `Envelope outcome '${value.outcome}' does not match result outcome '${value.result.outcome}'`,
259	          path: ["outcome"],
260	        });

260	        });
261	      }
262	    });
263	}
