123	export async function runProviderCommand(params: {
124	  provider: ProviderName;
125	  executable: string;
126	  args: string[];
127	  cwd: string;
128	  env?: Record<string, string | undefined>;
129	  timeoutMs: number;
130	}): Promise<{
131	  provider: ProviderName;
132	  stdout: string;
133	  stderr: string;
134	  exitCode: number;
135	  errorCode?: string;
136	}> {
137	  try {
138	    const result = await execFileAsync(params.executable, params.args, {
139	      cwd: params.cwd,
140	      env: {
141	        ...process.env,
142	        ...params.env,
143	      },
144	      timeout: params.timeoutMs,
145	    });
146	
147	    return {
148	      provider: params.provider,
149	      stdout: redactSensitiveText(result.stdout.trim()),
150	      stderr: redactSensitiveText(result.stderr.trim()),
151	      exitCode: 0,
152	    };
153	  } catch (error) {
154	    const failed = error as {
155	      code?: string | number;
156	      stdout?: string;
157	      stderr?: string;
158	      message?: string;
159	    };
160	
161	    return {
162	      provider: params.provider,
163	      stdout: redactSensitiveText(failed.stdout?.trim() ?? ""),
164	      stderr: redactSensitiveText(
165	        failed.stderr?.trim() ?? failed.message ?? String(error)
166	      ),
167	      exitCode:
168	        typeof failed.code === "number" ? failed.code : 1,
169	      errorCode:
170	        typeof failed.code === "string" ? failed.code : undefined,
171	    };
172	  }
173	}

